import asyncio
import time
import httpx
from dataclasses import dataclass
from typing import Optional

@dataclass
class ClassifierChaosResult:
    completions_blocked: int
    completions_escaped: int          # any value > 0 is critical
    alert_fired_within_s: Optional[float]

    @property
    def passed(self) -> bool:
        return self.completions_escaped == 0

    def report(self) -> str:
        if self.completions_escaped > 0:
            return (
                f"[CRITICAL FAIL] {self.completions_escaped} completion(s) bypassed "
                "safety classifier -- fail-open behavior detected."
            )
        alert_str = (
            f"alert fired in {self.alert_fired_within_s:.1f}s"
            if self.alert_fired_within_s else "alert NEVER fired"
        )
        return (
            f"[PASS] {self.completions_blocked} completions blocked. {alert_str}."
        )


async def run_classifier_outage_experiment(
    classifier_proxy_url: str,
    injection_duration_s: int = 60,
) -> ClassifierChaosResult:
    # Enable 503 chaos via Toxiproxy
    async with httpx.AsyncClient() as client:
        await client.post(f"{classifier_proxy_url}/toxics", json={
            "name": "classifier_down",
            "type": "timeout",
            "attributes": {"timeout": 0},
        })

    blocked, escaped = 0, 0
    for prompt in [f"Test prompt {i}" for i in range(20)]:
        try:
            response = await call_llm_pipeline(prompt)   # project-specific
            if response.status != "blocked_by_classifier":
                escaped += 1
            else:
                blocked += 1
        except Exception:
            blocked += 1   # errors are acceptable -- fail-closed

    await asyncio.sleep(injection_duration_s)

    # Disable chaos
    async with httpx.AsyncClient() as client:
        await client.delete(f"{classifier_proxy_url}/toxics/classifier_down")

    return ClassifierChaosResult(
        completions_blocked=blocked,
        completions_escaped=escaped,
        alert_fired_within_s=None,  # check alert system separately
    )
